    private static FrameworkElement Metric(string title,string textBinding,string scoreBinding,string color){var s=new StackPanel{Margin=new Thickness(0,16,0,0)};var row=new Grid();row.ColumnDefinitions.Add(new ColumnDefinition());row.ColumnDefinitions.Add(new ColumnDefinition{Width=GridLength.Auto});row.Children.Add(new TextBlock{Text=title,FontSize=11});var value=new TextBlock{FontFamily=new FontFamily("Consolas"),FontSize=11};value.SetBinding(TextBlock.TextProperty,new Binding(textBinding));Grid.SetColumn(value,1);row.Children.Add(value);s.Children.Add(row);var bar=new ProgressBar{Maximum=2000,Height=6,Margin=new Thickness(0,7,0,0),Foreground=(Brush)new BrushConverter().ConvertFromString(color)!};bar.SetBinding(RangeBase.ValueProperty,new Binding(scoreBinding){Mode=BindingMode.OneWay});s.Children.Add(bar);return s;}
