    private void ForceProgressBindingsOneWay(){foreach(var p in Descendants<ProgressBar>(this)){if(BindingOperations.GetBinding(p,RangeBase.ValueProperty)is not Binding b||b.Path is null)continue;p.SetBinding(RangeBase.ValueProperty,new Binding(b.Path.Path){Mode=BindingMode.OneWay});}}
    private static IEnumerable<T> Descendants<T>(DependencyObject root)where T:DependencyObject{foreach(var child in LogicalTreeHelper.GetChildren(root).OfType<DependencyObject>()){if(child is T match)yield return match;foreach(var nested in Descendants<T>(child))yield return nested;}}
    private async void OnLoaded(object sender,RoutedEventArgs e){try{await _viewModel.InitializeAsync(_monitorCancellation.Token);_monitorTask=MonitorLoopAsync(_monitorCancellation.Token);}catch(OperationCanceledException){}catch(Exception ex){MessageBox.Show(this,ex.Message,"초기화 오류",MessageBoxButton.OK,MessageBoxImage.Warning);}}
    private async Task MonitorLoopAsync(CancellationToken token){using var timer=new PeriodicTimer(TimeSpan.FromMilliseconds(500));while(await timer.WaitForNextTickAsync(token)){if(_benchmarkActive)continue;try{await _viewModel.RefreshMetricsAsync(token);CheckAlerts();}catch(OperationCanceledException)when(token.IsCancellationRequested){break;}catch{}}}
    private void CheckAlerts(){if(DateTimeOffset.Now-_lastAlert<TimeSpan.FromMinutes(5))return;static double First(string s)=>double.TryParse(new string(s.TakeWhile(c=>char.IsDigit(c)||c=='.').ToArray()),NumberStyles.Float,CultureInfo.InvariantCulture,out var v)?v:0;var cpu=First(_viewModel.CpuValue);var memory=First(_viewModel.MemoryDetail);var tempText=_viewModel.TemperatureValue.Replace("CPU ","");var temperature=First(tempText);string? warning=cpu>=95?$"CPU 사용률이 {cpu:0}%입니다.":memory>=90?$"메모리 사용률이 {memory:0}%입니다.":temperature>=90?$"CPU 온도가 {temperature:0}°C입니다.":null;if(warning is null)return;_lastAlert=DateTimeOffset.Now;_tray.ShowBalloonTip(5000,"System Checker 경고",warning,Forms.ToolTipIcon.Warning);}
